previewCss:
.darma-loader-darma-custom-393 {color: var(--loader-color, #2563eb);
  --loader-secondary-color: #38bdf8;
  --loader-bg: #ffffff;
  width: 20px;
  aspect-ratio: 1;
  border-radius: 50%;
  background: currentColor;
  box-shadow: 0 0 0 0 color-mix(in srgb, currentColor 25%, transparent);
  animation: darma-loader-darma-custom-393-l2 1.5s infinite linear;
  position: relative;
}.darma-loader-darma-custom-393:before,.darma-loader-darma-custom-393:after {content: "";
  position: absolute;
  inset: 0;
  border-radius: inherit;
  box-shadow: 0 0 0 0 color-mix(in srgb, currentColor 25%, transparent);
  animation: inherit;
  animation-delay: -0.5s;
}.darma-loader-darma-custom-393:before {animation-delay: -1s;
}@keyframes darma-loader-darma-custom-393-l2 {100% {box-shadow: 0 0 0 40px #0000}}

